<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/bootstrap.php';
try {
    $pdo=connectDatabase();$user=requireCustomer($pdo);$today=date('Y-m-d');$now=date('H:i:s');
    $active=$pdo->prepare("SELECT a.*,m.name AS mechanic_name,m.role_title FROM appointments a INNER JOIN mechanics m ON m.id=a.mechanic_id WHERE a.user_id=:user_id AND a.status='scheduled' AND (a.appointment_date>:future_date OR (a.appointment_date=:current_date AND (a.appointment_time IS NULL OR a.appointment_time>:current_time))) ORDER BY a.appointment_date,a.appointment_time LIMIT 1");
    $active->execute(['user_id'=>$user['id'],'future_date'=>$today,'current_date'=>$today,'current_time'=>$now]);$appointment=$active->fetch()?:null;
    $history=$pdo->prepare("SELECT a.*,m.name AS mechanic_name FROM appointments a INNER JOIN mechanics m ON m.id=a.mechanic_id WHERE a.user_id=:user_id AND (a.status='completed' OR a.appointment_date<:past_date OR (a.appointment_date=:current_date AND a.appointment_time IS NOT NULL AND a.appointment_time<=:current_time)) ORDER BY a.appointment_date DESC,a.appointment_time DESC");
    $history->execute(['user_id'=>$user['id'],'past_date'=>$today,'current_date'=>$today,'current_time'=>$now]);$historyAppointments=$history->fetchAll();
} catch(Throwable $error){error_log($error->getMessage());exit('Database connection failed.');}
$flash=pullFlash();
?>
