<section class="dashboard-grid"><article class="account-details strong-card"><div class="section-heading"><div><span class="section-icon">◎</span><p class="section-kicker">Identity</p><h2>Account Information</h2></div></div><dl class="details-list"><div><dt>Customer Name</dt><dd><?= e($user['full_name']) ?></dd></div><div><dt>Username</dt><dd><?= e($user['username']) ?></dd></div><div><dt>Phone</dt><dd><?= e($user['phone']) ?></dd></div><div><dt>Role</dt><dd><span class="role-badge customer">Customer</span></dd></div></dl></article>
<article class="appointment-summary strong-card"><div class="section-heading"><div><span class="section-icon">▣</span><p class="section-kicker">Current booking</p><h2>My Appointment</h2></div></div><?php if($appointment): ?><dl class="details-list"><div><dt>Mechanic</dt><dd><?= e($appointment['mechanic_name']) ?></dd></div><div><dt>Date</dt><dd><?= e(date('d M Y',strtotime($appointment['appointment_date']))) ?></dd></div><div><dt>Time</dt><dd><?= $appointment['appointment_time']!==null?e(date('h:i A',strtotime($appointment['appointment_time']))):'Waiting for admin assignment' ?></dd></div><div><dt>Car Registration</dt><dd><?= e($appointment['car_license']) ?></dd></div><div><dt>Engine Number</dt><dd><?= e($appointment['car_engine']) ?></dd></div><div><dt>Address</dt><dd><?= e($appointment['address']) ?></dd></div></dl><p class="single-appointment-note">You can book another appointment after this appointment time has passed.</p><?php else: ?><div class="empty-appointment"><span>▣</span><h3>No upcoming appointment</h3><p>You can book your next appointment now.</p><a class="btn btn-primary" href="<?= e(appUrl('index.php#booking')) ?>">Book Appointment</a></div><?php endif; ?></article></section>
<section class="appointment-history strong-card" id="history"><div class="section-heading"><div><span class="section-icon">↻</span><p class="section-kicker">Completed appointments</p><h2>Appointment History</h2></div><span class="history-count"><?= count($historyAppointments) ?></span></div><?php if($historyAppointments): ?><label class="history-search" for="historySearch">Search history<input class="form-control" id="historySearch" type="search" placeholder="Date, mechanic, registration or engine number"></label><div class="history-list" id="historyList"><?php foreach($historyAppointments as $item): ?><article><div><strong><?= e(date('d M Y',strtotime($item['appointment_date']))) ?></strong><small><?= $item['appointment_time']!==null?e(date('h:i A',strtotime($item['appointment_time']))):'Time not assigned' ?></small></div><div><strong><?= e($item['mechanic_name']) ?></strong><small><?= e($item['car_license']) ?> · <?= e($item['car_engine']) ?></small></div><span>Completed</span></article><?php endforeach; ?></div><p class="history-empty" id="historyNoResults" hidden>No history records match your search.</p><?php else: ?><p class="history-empty">Past appointments will appear here after their scheduled time has passed.</p><?php endif; ?></section>
</main><script src="<?= e(appUrl('assets/js/history.js')) ?>"></script></body></html>
